SELECT u.id FROM users u WHERE u.deleted_at IS NULL AND ( EXISTS ( SELECT 1 FROM purchases pu INNER JOIN products p ON p.id = pu.product_id WHERE pu.user_id = u.id AND pu.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) AND p.category_id IN
#{categoryId}
) OR EXISTS ( SELECT 1 FROM reviews r INNER JOIN products p ON p.id = r.product_id WHERE r.user_id = u.id AND r.deleted_at IS NULL AND r.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) AND p.category_id IN
#{categoryId}
) OR EXISTS ( SELECT 1 FROM favorites f INNER JOIN products p ON p.id = f.product_id WHERE f.user_id = u.id AND p.category_id IN
#{categoryId}
) ) ORDER BY u.id

SELECT u.id AS userId, u.email, u.gender, u.birth, ( SELECT LISTAGG(DISTINCT c.name, ',') WITHIN GROUP (ORDER BY c.name) FROM purchases pu INNER JOIN products p ON p.id = pu.product_id INNER JOIN categories c ON c.id = p.category_id WHERE pu.user_id = u.id AND pu.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) ) AS purchaseCategories, ( SELECT COUNT(*) FROM purchases pu INNER JOIN products p ON p.id = pu.product_id WHERE pu.user_id = u.id AND pu.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) AND p.category_id IN
#{categoryId}
) AS purchaseCount, ( SELECT LISTAGG(DISTINCT c.name, ',') WITHIN GROUP (ORDER BY c.name) FROM reviews r INNER JOIN products p ON p.id = r.product_id INNER JOIN categories c ON c.id = p.category_id WHERE r.user_id = u.id AND r.deleted_at IS NULL AND r.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) ) AS reviewCategories, ( SELECT COUNT(*) FROM reviews r WHERE r.user_id = u.id AND r.deleted_at IS NULL AND r.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) ) AS reviewCount, ( SELECT LISTAGG(DISTINCT c.name, ',') WITHIN GROUP (ORDER BY c.name) FROM favorites f INNER JOIN products p ON p.id = f.product_id INNER JOIN categories c ON c.id = p.category_id WHERE f.user_id = u.id ) AS favoriteCategories, ( SELECT COUNT(*) FROM favorites f WHERE f.user_id = u.id ) AS favoriteCount, ( SELECT AVG(r.rating) FROM reviews r WHERE r.user_id = u.id AND r.deleted_at IS NULL AND r.created_at >= ADD_MONTHS(SYSTIMESTAMP, -#{recentMonths}) ) AS averageRating FROM users u WHERE u.deleted_at IS NULL AND u.id IN
#{userId}
ORDER BY u.id
